from dataclasses import dataclass, field
from enum import Enum

class SOC2Category(str, Enum):
    CC = "common_criteria"        # Security — mandatory
    A  = "availability"
    C  = "confidentiality"
    P  = "privacy"
    PI = "processing_integrity"

@dataclass
class SOC2Criterion:
    criterion_id: str             # e.g. "CC6.1"
    category: SOC2Category
    description: str
    genai_implementation: str     # how this criterion is addressed in GenAI
    controls: list[str]           # control IDs that satisfy this criterion
    ai_specific: bool = False     # True if this is a GenAI extension beyond standard

@dataclass
class SOC2ControlMap:
    """
    Bidirectional mapping: criterion → controls and control → criteria.
    Used to generate compliance coverage reports and audit evidence packages.
    """
    mappings: list[SOC2Criterion] = field(default_factory=list)

    def criteria_for_control(self, control_id: str) -> list[SOC2Criterion]:
        return [m for m in self.mappings if control_id in m.controls]

    def controls_for_criterion(self, criterion_id: str) -> list[str]:
        for m in self.mappings:
            if m.criterion_id == criterion_id:
                return m.controls
        return []

    def coverage_by_category(self) -> dict[str, dict]:
        from collections import defaultdict
        by_cat: dict[str, list] = defaultdict(list)
        for m in self.mappings:
            by_cat[m.category.value].append(m)
        return {
            cat: {
                "total_criteria": len(criteria),
                "criteria_ids":   [c.criterion_id for c in criteria],
                "controls_referenced": list({ctrl for c in criteria for ctrl in c.controls}),
            }
            for cat, criteria in by_cat.items()
        }
